INSERT INTO `bai_viet` (`id`, `user_id`, `tieu_de`, `minh_hoa`, `noi_dung`, `cat`, `view`, `date_post`) VALUES
(1, 1, 'Hơn 190 tỷ USD kiều hối về Việt Nam trong 30 năm', '/uploads/minh-hoa/hon-190-ty-usd-kieu-hoi-ve-viet-nam-trong-30-nam-1710422954.jpg', '<p class=\"description\">Lượng kiều hối về Việt Nam giai đoạn 1993-2022 đạt tr&ecirc;n 190 tỷ USD, gần bằng lượng vốn FDI giải ng&acirc;n.</p>\r\n<article class=\"fck_detail \">\r\n<p class=\"Normal\">Theo số liệu đưa ra tại Hội nghị ph&aacute;t huy nguồn lực kiều b&agrave;o, kết nối địa phương, doanh nghiệp h&ocirc;m 27/12, cộng đồng người Việt ở nước ngo&agrave;i hiện khoảng 6 triệu người, tốc độ tăng trưởng khoảng 5% một năm. Kiều b&agrave;o hiện sinh sống tại hơn 130 quốc gia, v&ugrave;ng l&atilde;nh thổ, trong đ&oacute; 80% ở c&aacute;c nước ph&aacute;t triển.</p>\r\n<p class=\"Normal\">Bộ Ngoại giao cũng ước t&iacute;nh, lực lượng người Việt ra nước ngo&agrave;i l&agrave;m việc khoảng 130.000-150.000 người mỗi năm, đ&oacute;ng g&oacute;p về t&agrave;i ch&iacute;nh, v&agrave; trở th&agrave;nh nguồn nh&acirc;n lực cho đất nước. C&aacute;c doanh nh&acirc;n Việt ở nước ngo&agrave;i cũng l&agrave; lực lượng t&iacute;ch cực trong việc đưa h&agrave;ng Việt th&acirc;m nhập v&agrave;o thị trường nhiều nước.</p>\r\n<p class=\"Normal\">Lượng kiều hối gửi về nước t&iacute;nh từ năm 1993 (năm đầu ti&ecirc;n thống k&ecirc; kiều hối) đến năm 2022 đạt tr&ecirc;n 190 tỷ USD, gần bằng nguồn vốn FDI đ&atilde; giải ng&acirc;n trong c&ugrave;ng kỳ.</p>\r\n<p class=\"Normal\">Năm ngo&aacute;i, lượng kiều hối đạt 19 tỷ USD, tăng 5% so với năm 2021, đưa Việt Nam nằm trong top 10 quốc gia tr&ecirc;n thế giới về nhận kiều hối. Tại b&aacute;o c&aacute;o \"Điểm lại th&aacute;ng 8/2023\", Ng&acirc;n h&agrave;ng Thế giới dự b&aacute;o kiều hối của Việt Nam năm 2023 đạt 14 tỷ USD v&agrave; 14,4 tỷ USD trong năm 2024. C&ograve;n số liệu mới nhất của Ng&acirc;n h&agrave;ng Nh&agrave; nước chi nh&aacute;nh TP HCM - địa phương chiếm hơn một nửa lượng kiều hối cả nước, cho biết trong 11 th&aacute;ng, TP HCM n&agrave;y đ&atilde; nhận gần 9 tỷ USD kiều hối, tăng 35% so với năm 2022, gần gấp 3 lần vốn FDI.</p>\r\n<p class=\"Normal\"><img src=\"../uploads/hinh-anh/screenshot1-1710422911.png\" alt=\"\" width=\"883\" height=\"540\"></p>\r\n<p class=\"Normal\">Thực tế, kiều hối l&agrave; một trong những nguồn cung g&oacute;p phần bảo đảm quan hệ cung cầu ngoại tệ, đồng thời hỗ trợ hiệu quả cho ch&iacute;nh s&aacute;ch tiền tệ, tỷ gi&aacute; v&agrave; thị trường ngoại hối. Điều n&agrave;y lại c&agrave;ng c&oacute; &yacute; nghĩa hơn trong bối cảnh c&aacute;c đồng tiền mạnh biến động, lạm ph&aacute;t tại một số quốc gia g&acirc;y &aacute;p lực nhất định đến tỷ gi&aacute; v&agrave; mối quan hệ tỷ gi&aacute; - l&atilde;i suất v&agrave; lạm ph&aacute;t.</p>\r\n<p class=\"Normal\">Theo số liệu ch&iacute;nh thức từ Ng&acirc;n h&agrave;ng Nh&agrave; nước, kiều hối về Việt Nam mỗi năm tr&ecirc;n 10 tỷ USD. C&ograve;n nếu theo ước t&iacute;nh của Ng&acirc;n h&agrave;ng Thế giới (WB) v&agrave; Tổ chức hợp t&aacute;c quốc tế về người di cư, trung b&igrave;nh ba năm gần đ&acirc;y Việt Nam nhận l&ecirc;n tới 17-18 tỷ USD kiều hối mỗi năm.</p>\r\n<p class=\"Normal\">Ngo&agrave;i ra, t&iacute;nh đến cuối năm 2022, kiều b&agrave;o từ 35 quốc gia v&agrave; v&ugrave;ng l&atilde;nh thổ đ&atilde; đầu tư 385 dự &aacute;n FDI tại 42 địa phương ở Việt Nam với tổng số vốn đăng k&yacute; 1,72 tỷ USD, g&oacute;p phần th&uacute;c đẩy ph&aacute;t triển kinh tế - x&atilde; hội, tạo việc l&agrave;m cho lao động ở địa phương v&agrave; tăng nguồn thu từ thuế cho ng&acirc;n s&aacute;ch nh&agrave; nước.</p>\r\n</article>', '1', 0, '1710422954'),
(2, 1, 'Giá vàng miếng tăng vọt', '/uploads/minh-hoa/gia-vang-mieng-tang-vot-1710423139.jpg', '<p class=\"description\">Sau khi tăng 300.000-800.000 đồng đầu ng&agrave;y, mỗi lượng v&agrave;ng miếng trưa nay đắt th&ecirc;m nửa triệu đồng, l&ecirc;n 81,5 triệu đồng.</p>\r\n<article class=\"fck_detail \">\r\n<p class=\"Normal\">L&uacute;c 11h, gi&aacute; v&agrave;ng miếng tại SJC tăng th&ecirc;m nửa triệu đồng cả hai chiều mua b&aacute;n so với đầu s&aacute;ng, l&ecirc;n 79,5 - 81,5 triệu đồng. Mức n&agrave;y cao hơn cuối ng&agrave;y h&ocirc;m qua 800.000 đồng đến 1,3 triệu đồng. Như vậy so với đỉnh lịch sử, mỗi lượng v&agrave;ng miếng hiện chỉ k&eacute;m 1 triệu đồng.</p>\r\n<p class=\"Normal\">Trước đ&oacute; mở cửa ng&agrave;y, c&aacute;c nh&agrave; v&agrave;ng điều chỉnh&nbsp;gi&aacute; v&agrave;ng&nbsp;trong nước theo xu hướng đi l&ecirc;n của thế giới.</p>\r\n<p class=\"Normal\">Khoảng 9h, C&ocirc;ng ty V&agrave;ng bạc đ&aacute; qu&yacute; S&agrave;i G&ograve;n (SJC) yết gi&aacute; mua b&aacute;n tại 79 - 81 triệu đồng, tăng 800.000 đồng ở chiều mua v&agrave;o v&agrave; 300.000 đồng chiều b&aacute;n ra. Diễn biến n&agrave;y tr&aacute;i ngược với h&ocirc;m qua khi c&oacute; l&uacute;c mỗi lượng \"bốc hơi\" hơn 2 triệu đồng.</p>\r\n<p class=\"Normal\">Ch&ecirc;nh lệch gi&aacute; mua b&aacute;n hiện được thu hẹp về v&ugrave;ng 2 triệu một lượng. So với mức đỉnh thiết lập c&aacute;ch đ&acirc;y hai ng&agrave;y, mỗi lượng v&agrave;ng miếng đang thấp hơn khoảng 1,5 triệu đồng.</p>\r\n<p class=\"Normal\">&nbsp;</p>\r\n<div class=\"embed-container\"><iframe style=\"width: 867px; height: 1445px;\" src=\"https://flo.uri.sh/visualisation/17147640/embed\" width=\"867\" height=\"1445\" frameborder=\"0\" scrolling=\"no\" data-src=\"https://flo.uri.sh/visualisation/17147640/embed\"></iframe></div>\r\n<p>&nbsp;</p>\r\n<p class=\"Normal\">V&agrave;ng nhẫn trơn 24K tại SJC đầu ng&agrave;y cũng tăng 500.000 đồng l&ecirc;n 67,6 - 68,9 triệu một lượng. Tại Bảo T&iacute;n Minh Ch&acirc;u, nhẫn trơn l&ecirc;n gần 68,7 - 70,2 triệu, tăng 1,5 triệu đồng so với cuối ng&agrave;y h&ocirc;m qua. So với mức đỉnh, mỗi lượng nhẫn trơn tuỳ thương hiệu hiện thấp hơn 1-1,5 triệu đồng.</p>\r\n<p class=\"Normal\">Sau khi giảm mạnh 20 USD, gi&aacute; v&agrave;ng thế giới lại đảo chiều đi l&ecirc;n trong 24 giờ qua. 9h theo giờ H&agrave; Nội, gi&aacute; v&agrave;ng thế giới tăng 15 USD l&ecirc;n 2.174 USD mỗi ounce, quy đổi theo tỷ gi&aacute; Vietcombank tương đương 65,1 triệu đồng một lượng.</p>\r\n<figure class=\"tplCaption action_thumb_added\" data-size=\"true\">\r\n<div class=\"fig-picture\"><picture><source srcset=\"https://i1-kinhdoanh.vnecdn.net/2024/03/14/Vang-Ngoc-Thanh-16-9135-1710383309.jpg?w=680&amp;h=0&amp;q=100&amp;dpr=1&amp;fit=crop&amp;s=6RGXzreySwNyC4WX-HsXlg 1x, https://i1-kinhdoanh.vnecdn.net/2024/03/14/Vang-Ngoc-Thanh-16-9135-1710383309.jpg?w=1020&amp;h=0&amp;q=100&amp;dpr=1&amp;fit=crop&amp;s=if8wr3LmnLwEa6ytCSqAFw 1.5x, https://i1-kinhdoanh.vnecdn.net/2024/03/14/Vang-Ngoc-Thanh-16-9135-1710383309.jpg?w=680&amp;h=0&amp;q=100&amp;dpr=2&amp;fit=crop&amp;s=XmgzeU9KMe2fa-09ErvYSw 2x\" data-srcset=\"https://i1-kinhdoanh.vnecdn.net/2024/03/14/Vang-Ngoc-Thanh-16-9135-1710383309.jpg?w=680&amp;h=0&amp;q=100&amp;dpr=1&amp;fit=crop&amp;s=6RGXzreySwNyC4WX-HsXlg 1x, https://i1-kinhdoanh.vnecdn.net/2024/03/14/Vang-Ngoc-Thanh-16-9135-1710383309.jpg?w=1020&amp;h=0&amp;q=100&amp;dpr=1&amp;fit=crop&amp;s=if8wr3LmnLwEa6ytCSqAFw 1.5x, https://i1-kinhdoanh.vnecdn.net/2024/03/14/Vang-Ngoc-Thanh-16-9135-1710383309.jpg?w=680&amp;h=0&amp;q=100&amp;dpr=2&amp;fit=crop&amp;s=XmgzeU9KMe2fa-09ErvYSw 2x\"><img class=\"lazy lazied\" src=\"https://i1-kinhdoanh.vnecdn.net/2024/03/14/Vang-Ngoc-Thanh-16-9135-1710383309.jpg?w=680&amp;h=0&amp;q=100&amp;dpr=1&amp;fit=crop&amp;s=6RGXzreySwNyC4WX-HsXlg\" alt=\"V&agrave;ng miếng SJC giao dịch tại cửa h&agrave;ng. Ảnh: Đ&igrave;nh Văn\" loading=\"lazy\" data-src=\"https://i1-kinhdoanh.vnecdn.net/2024/03/14/Vang-Ngoc-Thanh-16-9135-1710383309.jpg?w=680&amp;h=0&amp;q=100&amp;dpr=1&amp;fit=crop&amp;s=6RGXzreySwNyC4WX-HsXlg\" data-ll-status=\"loaded\"></picture></div>\r\n<figcaption>\r\n<p class=\"Image\">V&agrave;ng miếng SJC giao dịch tại cửa h&agrave;ng. Ảnh:&nbsp;<em>Đ&igrave;nh Văn</em></p>\r\n</figcaption>\r\n</figure>\r\n<p class=\"Normal\">Gi&aacute; v&agrave;ng trong nước biến động mạnh hơn so với thế giới, hiện ch&ecirc;nh lệch giữa gi&aacute; v&agrave;ng miếng v&agrave; thế giới dao động 16-17 triệu đồng, c&ograve;n v&agrave;ng nhẫn v&ecirc;nh khoảng 4-5 triệu đồng một lượng, t&ugrave;y thời điểm trong ng&agrave;y.</p>\r\n<p class=\"Normal\">Ghi nhận tại TP HCM, giao dịch ở c&aacute;c thương hiệu v&agrave;ng như DOJI, PNJ kh&aacute; trầm lắng. Mặt h&agrave;ng nhẫn trơn sau gần một th&aacute;ng \"ch&aacute;y\" h&agrave;ng hiện cũng đ&atilde; l&ecirc;n kệ trở lại v&agrave; kh&aacute; dồi d&agrave;o số lượng 1-5.</p>\r\n<p class=\"Normal\">Tr&ecirc;n thị trường ngoại hối, gi&aacute; USD trong ng&acirc;n h&agrave;ng c&oacute; xu hướng đi l&ecirc;n 3 ng&agrave;y qua. Tỷ gi&aacute; tại Vietcombank s&aacute;ng nay l&agrave; 24.480 - 24.850 đồng, tăng 60 đồng so với đầu tuần. C&ograve;n gi&aacute; USD tại c&aacute;c điểm thu đổi ngoại tệ tr&ecirc;n thị trường chợ đen lại hạ nhiệt sau một đợt tăng d&agrave;i.</p>\r\n</article>', '1', 0, '1710423139'),
(3, 1, 'Việt Nam thu 2,9 tỷ USD từ bán gỗ dăm, viên nén', '/uploads/minh-hoa/viet-nam-thu-2-9-ty-usd-tu-ban-go-dam-vien-nen-1710423244.jpg', '<p class=\"description\">Việt Nam thu 2,9 tỷ USD trong năm ngo&aacute;i từ b&aacute;n gỗ dăm, vi&ecirc;n n&eacute;n sang Trung Quốc, Nhật Bản, H&agrave;n Quốc.</p>\r\n<article class=\"fck_detail \">\r\n<p class=\"Normal\">B&aacute;o c&aacute;o to&agrave;n ng&agrave;nh gỗ năm 2023 của Hiệp hội Gỗ v&agrave; L&acirc;m sản Việt Nam cho biết, ngo&agrave;i c&aacute;c sản phẩm gỗ chủ lực, gỗ dăm v&agrave; vi&ecirc;n n&eacute;n đ&oacute;ng g&oacute;p đ&aacute;ng kể cho ng&agrave;nh n&agrave;y.</p>\r\n<p class=\"Normal\">Cụ thể, Việt Nam xuất khẩu gần 14,4 triệu tấn dăm gỗ, đạt 2,2 tỷ USD, chiếm 16,8% tổng kim ngạch xuất khẩu của ng&agrave;nh gỗ. So với năm 2022, xuất khẩu dăm gỗ giảm 8,8% về lượng v&agrave; giảm 20,4% về gi&aacute; trị. Tương tự, với vi&ecirc;n n&eacute;n gỗ, nước ta xuất khẩu 4,67 triệu tấn, trị gi&aacute; gần 700 triệu USD, chiếm 5,2% tổng kim ngạch ng&agrave;nh n&agrave;y.</p>\r\n<p class=\"Normal\">Hiện, 2 sản phẩm tr&ecirc;n xuất đi tr&ecirc;n 13 quốc gia v&agrave; v&ugrave;ng l&atilde;nh thổ. Trung Quốc, Nhật Bản l&agrave; hai thị trường nhập khẩu lớn nhất của Việt Nam, chiếm 92,4% tổng sản lượng v&agrave; 92,2% tổng gi&aacute; trị xuất khẩu.</p>\r\n<figure class=\"tplCaption action_thumb_added\" data-size=\"true\">\r\n<div class=\"fig-picture\"><picture><source srcset=\"https://i1-kinhdoanh.vnecdn.net/2024/03/13/vien-nen-go-4642-jpeg-8544-1710339050.jpg?w=680&amp;h=0&amp;q=100&amp;dpr=1&amp;fit=crop&amp;s=p5jLJcTo2xfRfanYQBTN7g 1x, https://i1-kinhdoanh.vnecdn.net/2024/03/13/vien-nen-go-4642-jpeg-8544-1710339050.jpg?w=1020&amp;h=0&amp;q=100&amp;dpr=1&amp;fit=crop&amp;s=h3QAipPyDMxGZTCWNulFZQ 1.5x, https://i1-kinhdoanh.vnecdn.net/2024/03/13/vien-nen-go-4642-jpeg-8544-1710339050.jpg?w=680&amp;h=0&amp;q=100&amp;dpr=2&amp;fit=crop&amp;s=78ORqCGLRJ-ywydwa1uABw 2x\" data-srcset=\"https://i1-kinhdoanh.vnecdn.net/2024/03/13/vien-nen-go-4642-jpeg-8544-1710339050.jpg?w=680&amp;h=0&amp;q=100&amp;dpr=1&amp;fit=crop&amp;s=p5jLJcTo2xfRfanYQBTN7g 1x, https://i1-kinhdoanh.vnecdn.net/2024/03/13/vien-nen-go-4642-jpeg-8544-1710339050.jpg?w=1020&amp;h=0&amp;q=100&amp;dpr=1&amp;fit=crop&amp;s=h3QAipPyDMxGZTCWNulFZQ 1.5x, https://i1-kinhdoanh.vnecdn.net/2024/03/13/vien-nen-go-4642-jpeg-8544-1710339050.jpg?w=680&amp;h=0&amp;q=100&amp;dpr=2&amp;fit=crop&amp;s=78ORqCGLRJ-ywydwa1uABw 2x\"><img class=\"lazy lazied\" src=\"../uploads/hinh-anh/vien-nen-go-4642-jpeg-8544-1710339050-1710423265.jpg\" alt=\"Dăm gỗ v&agrave; vi&ecirc;n n&eacute;n gỗ được thị trường Trung Quốc, Nhật Bản ưa chuộng. Ảnh: nguyenlieudot\" width=\"639\" height=\"427\" loading=\"lazy\" data-src=\"https://i1-kinhdoanh.vnecdn.net/2024/03/13/vien-nen-go-4642-jpeg-8544-1710339050.jpg?w=680&amp;h=0&amp;q=100&amp;dpr=1&amp;fit=crop&amp;s=p5jLJcTo2xfRfanYQBTN7g\" data-ll-status=\"loaded\"></picture></div>\r\n<figcaption>\r\n<p class=\"Image\">Dăm gỗ v&agrave; vi&ecirc;n n&eacute;n gỗ được thị trường Trung Quốc, Nhật Bản ưa chuộng. Ảnh:&nbsp;<em>nguyenlieudot</em></p>\r\n</figcaption>\r\n</figure>\r\n<p class=\"Normal\">Theo Cục L&acirc;m nghiệp, trong năm 2023, to&agrave;n ng&agrave;nh khai th&aacute;c được khoảng 19 triệu ster củi (đơn vị t&iacute;nh thể t&iacute;ch của củi). Đ&acirc;y l&agrave; nguy&ecirc;n liệu đầu v&agrave;o chủ yếu cho sản xuất dăm gỗ v&agrave; vi&ecirc;n n&eacute;n. Ngo&agrave;i ra, phế phụ phẩm của ng&agrave;nh chế biến, sản xuất đồ gỗ như đầu mẩu, vụn, vỏ b&agrave;o, m&ugrave;n cưa... cũng được sử dụng để sản xuất vi&ecirc;n n&eacute;n v&agrave; dăm gỗ.</p>\r\n<p class=\"Normal\">N&oacute;i với&nbsp;<em>VnExpress</em>&nbsp;trước đ&oacute;, &ocirc;ng Nguyễn Ch&aacute;nh Phương, Gi&aacute;m đốc c&ocirc;ng ty Danh Mộc, Ph&oacute; chủ tịch Hiệp hội Mỹ nghệ v&agrave; Chế biến gỗ TP HCM (Hawa), cho biết từ th&aacute;ng 8 năm ngo&aacute;i đến nay, doanh số xuất khẩu gỗ v&agrave; c&aacute;c sản phẩm từ gỗ của Việt Nam tăng b&igrave;nh qu&acirc;n 3-5%. Th&aacute;ng 1, kim ngạch xuất khẩu gỗ v&agrave; sản phẩm gỗ thu về gần 1,5 tỷ USD, tăng hơn 72% so với c&ugrave;ng kỳ năm ngo&aacute;i v&agrave; đang tr&ecirc;n đ&agrave; tăng. Xuất khẩu dăm gỗ v&agrave; vi&ecirc;n n&eacute;n th&aacute;ng đầu năm đ&atilde; tăng tr&ecirc;n 22% so với c&ugrave;ng kỳ năm ngo&aacute;i.</p>\r\n<p class=\"Normal\">\"Với mức độ tăng trưởng mạnh như hiện nay, năm nay, Việt Nam c&oacute; thể đạt 17 tỷ USD\", &ocirc;ng Phương n&oacute;i.</p>\r\n<p class=\"Normal\">Tương tự, theo c&aacute;c doanh nghiệp xuất khẩu dăm gỗ, nh&oacute;m n&agrave;y c&ograve;n nhiều tiềm năng để ph&aacute;t triển. Vi&ecirc;n n&eacute;n gỗ kim ngạch c&oacute; thể đạt 1 tỷ USD trong thời gian tới.</p>\r\n</article>', '1', 0, '1710423244'),
(4, 1, 'Giá xăng giảm, dầu tăng', '/uploads/minh-hoa/gia-xang-giam-dau-tang-1710423421.jpg', '<p class=\"description\">Mỗi l&iacute;t xăng giảm 10-20 đồng, trong khi c&aacute;c mặt h&agrave;ng dầu tăng 70-300 đồng t&ugrave;y loại, từ 15h h&ocirc;m nay.</p>\r\n<article class=\"fck_detail \">\r\n<p class=\"Normal\">Theo điều h&agrave;nh của li&ecirc;n Bộ C&ocirc;ng Thương - T&agrave;i ch&iacute;nh h&ocirc;m nay, gi&aacute; xăng RON 95-III (loại phổ biến tr&ecirc;n thị trường) giảm 10 đồng, về 23.540 đồng một l&iacute;t; E5 RON 92 hạ 20 đồng, c&ograve;n 22.490 đồng một l&iacute;t.</p>\r\n<p class=\"Normal\">Tương tự, c&aacute;c mặt h&agrave;ng dầu cũng tăng v&agrave; c&oacute; gi&aacute; mới 16.430-20.700 đồng một l&iacute;t so với c&aacute;ch đ&acirc;y 7 ng&agrave;y.</p>\r\n<p class=\"Normal\">Gi&aacute; xăng, dầu&nbsp;thay đổi như sau:</p>\r\n<table border=\"1\" cellspacing=\"1\" cellpadding=\"1\" align=\"center\">\r\n<tbody>\r\n<tr>\r\n<td><strong>Mặt h&agrave;ng</strong></td>\r\n<td><strong>Gi&aacute; mới</strong></td>\r\n<td><strong>Thay đổi</strong></td>\r\n</tr>\r\n<tr>\r\n<td>Xăng RON 95-III</td>\r\n<td>23.540</td>\r\n<td>- 10</td>\r\n</tr>\r\n<tr>\r\n<td>Xăng E5 RON 92</td>\r\n<td>22.490</td>\r\n<td>- 20</td>\r\n</tr>\r\n<tr>\r\n<td>Dầu diesel</td>\r\n<td>20.540</td>\r\n<td>+ 70</td>\r\n</tr>\r\n<tr>\r\n<td>Dầu hoả</td>\r\n<td>20.700</td>\r\n<td>+ 100</td>\r\n</tr>\r\n<tr>\r\n<td>Dầu mazut</td>\r\n<td>16.430</td>\r\n<td>+ 300</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p class=\"Normal\"><em>Đơn vị: đồng/l&iacute;t hoặc kg, t&ugrave;y loại</em></p>\r\n<p class=\"Normal\">Như vậy, từ ng&agrave;y 4/1 đến nay, gi&aacute; xăng c&oacute; 6 lần tăng, 4 lần giảm. C&ograve;n dầu diesel c&oacute; 6 lần tăng, 4 giảm. Tương tự c&aacute;c kỳ trước, h&ocirc;m nay li&ecirc;n Bộ tiếp tục kh&ocirc;ng tr&iacute;ch, chi sử dụng từ Quỹ b&igrave;nh ổn gi&aacute; (trừ dầu mazut mức tr&iacute;ch lập l&agrave; 300 đồng một kg).</p>\r\n<div data-widget=\"obj\">\r\n<div id=\"chart-7868\" class=\"width_common mb20 fullscreen-inner\" data-component=\"true\" data-component-value=\"7868\" data-highcharts-chart=\"0\">\r\n<div id=\"highcharts-ouigery-0\" class=\"highcharts-container \" dir=\"ltr\"><img src=\"../uploads/hinh-anh/screenshot2-1710423378.png\" alt=\"\" width=\"871\" height=\"524\"></div>\r\n</div>\r\n</div>\r\n<p class=\"Normal\">Nh&agrave; điều h&agrave;nh cho biết gi&aacute; nhi&ecirc;n liệu biến động do chỉ số gi&aacute; ti&ecirc;u d&ugrave;ng (CPI) của Trung Quốc tăng, tồn kho dầu thương mại của Mỹ giảm mạnh hơn dự b&aacute;o.</p>\r\n<p class=\"Normal\">B&igrave;nh qu&acirc;n 7 ng&agrave;y, gi&aacute; xăng th&agrave;nh phẩm giảm kh&ocirc;ng đ&aacute;ng kể, dầu tăng 0,5-2,5%. Trong đ&oacute;, mỗi th&ugrave;ng xăng RON 95 hạ c&ograve;n 98,7 USD; dầu diesel l&ecirc;n 102,3 USD, dầu mazut 464,5 USD mỗi tấn.</p>\r\n</article>', '1', 0, '1710423421'),
(6, 1, 'Quy chế hoạt động ', '/uploads/minh-hoa/quy-che-hoat-dong-san-giao-dich-van-tai-ketnoivanchuyen-vn-1720689069.png', '<p style=\"text-align: center;\"><strong><span lang=\"EN-US\">QUY CHẾ HOẠT ĐỘNG S&Agrave;N GIAO DỊCH VẬN TẢI KETNOIVANCHUYEN.VN</span></strong></p>\r\n<p style=\"text-align: center;\"><em><span lang=\"EN-US\">V1.1 &ndash; &Aacute;P DỤNG TỪ NG&Agrave;Y 01/06/2024</span></em></p>\r\n<p><!-- [if !supportLists]--><strong><span lang=\"EN-US\">I.&nbsp;</span><span lang=\"EN-US\">GIỚI THIỆU VỀ S&Agrave;N GIAO DỊCH V&Acirc;̣N TẢI </span><span lang=\"EN-US\">KETNOIVANCHUYEN.VN</span></strong></p>\r\n<p><span lang=\"EN-US\">S&agrave;n giao dịch v&acirc;̣n tải ketnoivanchuyen c&oacute; t&ecirc;n miền Ketnoivanchuyen.vn l&agrave; Website trực tuy&ecirc;́n m&ocirc;i giới - k&ecirc;́t n&ocirc;́i&nbsp; v&agrave; hỗ trợ&nbsp; thực hi&ecirc;̣n giao dịch giữa đơn vị v&acirc;̣n tải (chủ xe v&acirc;̣n chuy&ecirc;̉n h&agrave;ng h&oacute;a) với nhau&nbsp; v&agrave; với c&aacute;c đơn vị chủ h&agrave;ng (c&oacute; h&agrave;ng h&oacute;a c&acirc;̀n v&acirc;̣n chuy&ecirc;̉n).</span></p>\r\n<p><span lang=\"EN-US\">S&agrave;n giao dịch v&acirc;̣n tải ketnoivanchuyen.vn do C&ocirc;ng ty Cổ phần Kết Nối Vận Chuyển MHGS đi&ecirc;̀u h&agrave;nh v&agrave; khai th&aacute;c theo gi&acirc;́y Đăng k&yacute; kinh doanh s&ocirc;́: 0110063355 do Sở KH&amp;ĐT Tp.HN c&acirc;́p ng&agrave;y 18 th&aacute;ng 07 năm 2022.</span></p>\r\n<p><!-- [if !supportLists]--><strong><span lang=\"EN-US\">II. </span><span lang=\"EN-US\">NGUY&Ecirc;N TẮC CHUNG&nbsp;</span></strong></p>\r\n<p><!-- [if !supportLists]--><span lang=\"EN-US\">1.&nbsp;</span><span lang=\"EN-US\">Website Ketnoivanchuyen.vn cung c&acirc;́p c&ocirc;ng cụ đ&ecirc;̉ Chủ xe (Đơn vị v&acirc;̣n tải ) v&agrave; Chủ h&agrave;ng (Đơn vị c&oacute; h&agrave;ng h&oacute;a cần vận chuyển) thực vi&ecirc;̣c đăng k&yacute; th&ocirc;ng tin giao dịch, bao g&ocirc;̀m:</span></p>\r\n<p><span lang=\"EN-US\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; + Đăng k&yacute; c&oacute; xe chở h&agrave;ng;</span></p>\r\n<p><span lang=\"EN-US\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; + Đăng k&yacute; nhu c&acirc;̀u v&acirc;̣n tải h&agrave;ng h&oacute;a;</span></p>\r\n<p><span lang=\"EN-US\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; + T&igrave;m ki&ecirc;́m xe chở h&agrave;ng;</span></p>\r\n<p><span lang=\"EN-US\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; + T&igrave;m ki&ecirc;́m nhu c&acirc;̀u v&acirc;̣n tải hang h&oacute;a;</span></p>\r\n<p><span lang=\"EN-US\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; + T&ocirc;̉ chức đ&acirc;́u th&acirc;̀u v&acirc;̣n tải;</span></p>\r\n<p><!-- [if !supportLists]--><strong><span lang=\"EN-US\">2. </span><span lang=\"EN-US\">N&ocirc;̣i dung đăng k&yacute; sẽ được đ&aacute;nh m&atilde; s&ocirc;́ v&agrave; được th&ocirc;ng b&aacute;o tr&ecirc;n Website ketnoivanchuyen.vn</span></strong></p>\r\n<p><!-- [if !supportLists]--><strong><span lang=\"EN-US\">3. </span><span lang=\"EN-US\">Đơn vị v&acirc;̣n tải v&agrave; Chủ h&agrave;ng sẽ li&ecirc;n h&ecirc;̣ với nhau th&ocirc;ng qua Website ketnoivanchuyen.vn. S&agrave;n giao dịch v&acirc;̣n tải Ketnoivanchuyen.vn &nbsp;sẽ l&agrave;m trung gian ki&ecirc;̉m chứng th&ocirc;ng tin của c&aacute;c b&ecirc;n v&agrave; phối hợp thực hiện hợp đồng vận tải th&ocirc;ng qua h&igrave;nh thức: </span></strong></p>\r\n<p><!-- [if !supportLists]--><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </span><!--[endif]--><span lang=\"EN-US\">Đại di&ecirc;̣n k&yacute; hợp đ&ocirc;̀ng với m&ocirc;̃i b&ecirc;n đ&ecirc;̉ thực hi&ecirc;̣n giao dịch cho Đơn vị v&acirc;̣n tải&nbsp; v&agrave; Chủ h&agrave;ng.</span></p>\r\n<p><span lang=\"EN-US\">H&agrave;ng h&oacute;a đăng k&yacute; giao dịch tr&ecirc;n Ketnoivanchuyen.vn phải&nbsp; tu&acirc;n thủ theo quy định của ph&aacute;p luật Việt Nam. Chủ h&agrave;ng phải ho&agrave;n to&agrave;n chịu tr&aacute;ch nhi&ecirc;̣m n&ecirc;́u đăng tin h&agrave;ng h&oacute;a sai với thực t&ecirc;́ hoặc h&agrave;ng h&oacute;a kh&ocirc;ng được ph&eacute;p giao dịch.</span></p>\r\n<p><span lang=\"EN-US\">Th&ocirc;ng tin xe v&agrave; h&agrave;ng h&oacute;a đăng tr&ecirc;n Website Ketnoivanchuyen.vn được thực hiện c&ocirc;ng khai, minh bạch, đảm bảo quyền lợi của c&aacute;c b&ecirc;n c&oacute; li&ecirc;n quan.</span></p>\r\n<p><span lang=\"EN-US\">Đơn vị v&acirc;̣n tải, Chủ h&agrave;ng v&agrave; c&aacute; nh&acirc;n người sử dụng kh&aacute;c c&acirc;̀n phải đăng k&yacute; l&agrave; Th&agrave;nh vi&ecirc;n của S&agrave;n giao dịch v&acirc;̣n tải trước khi thực hi&ecirc;̣n b&acirc;́t kỳ giao dịch n&agrave;o tr&ecirc;n Website Ketnoivanchuyen.vn. Vi&ecirc;̣c đăng k&yacute; th&agrave;nh vi&ecirc;n được thực hi&ecirc;̣n tự đ&ocirc;̣ng th&ocirc;ng qua vi&ecirc;̣c x&aacute;c nh&acirc;̣n th&ocirc;ng tin tr&ecirc;n email/s&ocirc;́ đi&ecirc;̣n thoại của người đăng k&yacute;. Tuy v&acirc;̣y, người đăng k&yacute; chỉ được xem l&agrave; Th&agrave;nh vi&ecirc;n sau khi S&agrave;n giao dịch v&acirc;̣n tải Ketnoivanchuyen.vn x&aacute;c thực th&ocirc;ng tin. Th&agrave;nh vi&ecirc;n tự chịu tr&aacute;ch nhi&ecirc;̣m bảo v&ecirc;̣ m&acirc;̣t kh&acirc;̉u v&agrave; t&iacute;nh ch&iacute;nh x&aacute;c trong vi&ecirc;̣c cung c&acirc;́p th&ocirc;ng tin cho S&agrave;n giao dịch v&acirc;̣n tải Ketnoivanchuyen.vn.</span></p>\r\n<p><span lang=\"EN-US\">Bằng vi&ecirc;̣c đăng k&yacute; th&agrave;nh vi&ecirc;n của S&agrave;n giao dịch v&acirc;̣n tải Ketnoivanchuyen.vn, Đơn vị v&acirc;̣n tải, Chủ xe v&agrave; c&aacute; nh&acirc;n đăng k&yacute; đ&atilde; đ&ocirc;̀ng &yacute; với c&aacute;c đi&ecirc;̀u khoản của Quy ch&ecirc;́ S&agrave;n giao dịch v&acirc;̣n tải Ketnoivanchuyen.vn.</span></p>\r\n<p><!-- [if !supportLists]--><strong><span lang=\"EN-US\">III.&nbsp;</span><span lang=\"EN-US\">QUY ĐỊNH CHUNG&nbsp;</span></strong></p>\r\n<p><!-- [if !supportLists]--><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </span><!--[endif]--><span lang=\"EN-US\">&ldquo;Ketnoivanchuyen.vn&rdquo; hoặc &ldquo;S&agrave;n giao dịch vận tải Ketnoivanchuyen.vn&rdquo;: l&agrave; s&agrave;n giao dịch vận tải c&oacute; t&ecirc;n miền l&agrave; ketnoivanchuyen.vn do C&ocirc;ng ty Cổ phần Kết nối vận chuyển To&agrave;n Cầu sở hữu v&agrave; vận h&agrave;nh. Th&agrave;nh vi&ecirc;n tr&ecirc;n website Ketnoivanchuyen.vn l&agrave; c&aacute;c thương nh&acirc;n, tổ chức, c&aacute; nh&acirc;n c&oacute; hoạt động thương mại hợp ph&aacute;p được Ketnoivanchuyen.vn ch&iacute;nh thức c&ocirc;ng nhận v&agrave; được ph&eacute;p sử dụng dịch vụ do website Ketnoivanchuyen.vn &nbsp;cung cấp.</span></p>\r\n<p><!-- [if !supportLists]--><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </span><!--[endif]--><span lang=\"EN-US\">Nguy&ecirc;n tắc n&agrave;y &aacute;p dụng cho c&aacute;c th&agrave;nh vi&ecirc;n đăng k&yacute; sử dụng c&aacute;c dịch vụ do Website Ketnoivanchuyen.vn cung cấp.</span></p>\r\n<p><!-- [if !supportLists]--><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </span><!--[endif]--><span lang=\"EN-US\">Thương nh&acirc;n, tổ chức, c&aacute; nh&acirc;n tham gia giao dịch tại Ketnoivanchuyen.vn tự do thỏa thuận tr&ecirc;n cơ sở t&ocirc;n trọng quyền v&agrave; lợi &iacute;ch hợp ph&aacute;p của c&aacute;c b&ecirc;n tham gia hoạt động th&ocirc;ng qua hợp đồng, kh&ocirc;ng tr&aacute;i với quy định của ph&aacute;p luật.</span></p>\r\n<p><!-- [if !supportLists]--><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </span><!--[endif]--><span lang=\"EN-US\">Th&ocirc;ng tin về thương nh&acirc;n, tổ chức, c&aacute; nh&acirc;n tham gia l&agrave; th&agrave;nh vi&ecirc;n tr&ecirc;n Website Ketnoivanchuyen.vn phải minh bạch v&agrave; ch&iacute;nh x&aacute;c.</span></p>\r\n<p><!-- [if !supportLists]--><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </span><!--[endif]--><span lang=\"EN-US\">Dịch vụ tham gia giao dịch tr&ecirc;n Website Ketnoivanchuyen.vn phải được ph&eacute;p kinh doanh, lưu h&agrave;nh v&agrave; kh&ocirc;ng thuộc c&aacute;c trường hợp cấm kinh doanh, cấm quảng c&aacute;o theo quy định của ph&aacute;p luật.</span></p>\r\n<p><!-- [if !supportLists]--><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </span><!--[endif]--><span lang=\"EN-US\">C&aacute;c nội dung trong bản Quy chế n&agrave;y phải tu&acirc;n thủ theo hệ thống ph&aacute;p luật hiện h&agrave;nh của Việt Nam. Th&agrave;nh vi&ecirc;n khi tham gia v&agrave;o Website Ketnoivanchuyen.vn phải tự t&igrave;m hiểu tr&aacute;ch nhiệm ph&aacute;p l&yacute; của m&igrave;nh đối với luật ph&aacute;p hiện h&agrave;nh của Việt Nam v&agrave; cam kết thực hiện đ&uacute;ng những nội dung trong Quy chế của Website Ketnoivanchuyen.vn.</span></p>\r\n<p><!-- [if !supportLists]--><strong><span lang=\"EN-US\">IV. &nbsp;</span><span lang=\"EN-US\">QUY TR&Igrave;NH GIAO DỊCH </span></strong></p>\r\n<p><span lang=\"EN-US\">Hướng dẫn sử dụng v&agrave; quy tr&igrave;nh <span style=\"color: rgb(224, 62, 45);\">(<a style=\"color: rgb(224, 62, 45);\" href=\"https://drive.google.com/file/d/1tNxshYKanTokRPkwLf-GANfbUXX38zgj/view\">tải tại đ&acirc;y</a>)</span></span></p>\r\n<p><!-- [if !supportLists]--><strong><span lang=\"EN-US\">V. &nbsp;</span><span lang=\"EN-US\">QUY TR&Igrave;NH THANH TO&Aacute;N </span></strong></p>\r\n<p><span lang=\"EN-US\">- Việc thanh to&aacute;n giữa chủ xe v&agrave; chủ h&agrave;ng được thực hi&ecirc;n theo từng hợp đồng vận tải cụ thể.</span></p>\r\n<p><span lang=\"EN-US\">- Trường hợp S&agrave;n ketnoivanchuyen.vn nhận ủy quyền k&yacute; hợp đồng với Chủ xe v&agrave; Chủ h&agrave;ng, việc thanh to&aacute;n cũng sẽ tu&acirc;n theo hợp đ&ograve;ng kinh tế đ&atilde; k&yacute;.</span></p>\r\n<p><span lang=\"EN-US\">- Thời điểm hiện tại, ketnoivanchuyen.vn chưa t&iacute;ch hợp c&ocirc;ng cụ thanh to&aacute;n trực tuyến Internet banking, n&ecirc;n việc thanh to&aacute;n với ketnoivanchuyen.vn sẽ hầu hết qua chuyển khoản.</span></p>\r\n<p><!-- [if !supportLists]--><strong><span lang=\"EN-US\">VI. </span><span lang=\"EN-US\">ĐẢM BẢO AN TO&Agrave;N GIAO DỊCH </span></strong></p>\r\n<p><span lang=\"EN-US\">S&agrave;n giao dịch v&acirc;̣n tải ketnoivanchuyen.vn chịu tr&aacute;ch nhi&ecirc;̣m ki&ecirc;̉m tra x&aacute;c thực th&ocirc;ng tin th&agrave;nh vi&ecirc;n tham gia giao dịch, nhằm đảm bảo t&acirc;́t cả c&aacute;c th&ocirc;ng tin giao dịch được c&ocirc;ng b&ocirc;́ l&agrave; chinh x&aacute;c nh&acirc;́t c&oacute; th&ecirc;̉. Tuy vậy, S&agrave;n ketnoivanchuyen kh&ocirc;ng chịu tr&aacute;ch nhiệm về những th&ocirc;ng tin cung cấp kh&ocirc;ng ch&iacute;nh x&aacute;c của c&aacute;c thanh vi&ecirc;n.</span></p>\r\n<p><span lang=\"EN-US\">Tất cả c&aacute;c giao dịch của kh&aacute;ch h&agrave;ng đ&ecirc;̀u được xử l&yacute;, gi&aacute;m s&aacute;t đ&acirc;̀y đủ, c&oacute; email th&ocirc;ng b&aacute;o x&aacute;c thực cho th&agrave;nh vi&ecirc;n li&ecirc;n quan ở từng giai đoạn.</span><span lang=\"EN-US\">&nbsp;</span></p>\r\n<p><!-- [if !supportLists]--><strong><span lang=\"EN-US\">VII. </span><span lang=\"EN-US\">BẢO VỆ TH&Ocirc;NG TIN C&Aacute; NH&Acirc;N TH&Agrave;NH VI&Ecirc;N </span></strong></p>\r\n<p><span lang=\"EN-US\">S&agrave;n giao dịch v&acirc;̣n tải ketnoivanchuyen.vn cam kết bảo mật th&ocirc;ng tin của th&agrave;nh vi&ecirc;n tuyệt đối.</span></p>\r\n<p><span lang=\"EN-US\">&nbsp;</span></p>\r\n<p><span lang=\"EN-US\">Việc thu thập v&agrave; sử dụng th&ocirc;ng tin của mỗi th&agrave;nh vi&ecirc;n chỉ được thực hiện khi c&oacute; sự đồng &yacute; của th&agrave;nh vi&ecirc;n ngoại trừ những trường hợp ph&aacute;p luật c&oacute; quy định kh&aacute;c.</span></p>\r\n<p><span lang=\"EN-US\">S&agrave;n giao dịch v&acirc;̣n tải ketnoivanchuyen.vn chỉ cung cấp th&ocirc;ng tin kh&aacute;ch h&agrave;ng cho b&ecirc;n thứ ba nếu c&oacute; sự đồng &yacute; của th&agrave;nh vi&ecirc;n hoặc theo y&ecirc;u cầu của cơ quan nh&agrave; nước theo quy định của ph&aacute;p luật.</span></p>\r\n<p><span lang=\"EN-US\">Sau khoảng thời gian 6 th&aacute;ng n&ecirc;́u th&agrave;nh vi&ecirc;n kh&ocirc;ng c&oacute; b&acirc;́t kỳ giao dịch n&agrave;o tr&ecirc;n S&agrave;n ketnoivanchuyen.vn, th&ocirc;ng tin của th&agrave;nh vi&ecirc;n sẽ bị hủy bỏ tự động v&agrave; kh&ocirc;ng được sử dụng v&agrave;o b&acirc;́t kỳ mục đ&iacute;ch n&agrave;o kh&aacute;c n&ecirc;́u chưa được sự cho ph&eacute;p của th&agrave;nh vi&ecirc;n n&agrave;y, ngoại trừ trường hợp được quy định tại c&aacute;c văn bản ph&aacute;p quy kh&aacute;c.</span></p>\r\n<p><!-- [if !supportLists]--><strong><span lang=\"EN-US\">VIII. </span><span lang=\"EN-US\">QUẢN L&Yacute; TH&Ocirc;NG TIN XẤU:</span></strong></p>\r\n<p><span lang=\"EN-US\">Th&ocirc;ng tin đăng k&yacute; L&ocirc; h&agrave;ng của Chủ h&agrave;ng phải thể hiện t&iacute;nh trung thực.</span></p>\r\n<p><span lang=\"EN-US\">H&agrave;ng h&oacute;a vận tải phải l&agrave; h&agrave;ng h&oacute;a được ph&eacute;p vận chuyển. Nếu l&agrave; h&agrave;ng qu&aacute; khổ - qu&aacute; tải Chủ h&agrave;ng phải th&ocirc;ng b&aacute;o r&otilde; tại mục M&ocirc; tả khi đăng k&yacute;. Nếu l&agrave; h&oacute;a cần c&oacute; giấy ph&eacute;p vận chuyển, th&agrave;nh vi&ecirc;n phải cung cấp th&ocirc;ng tin giấy ph&eacute;p li&ecirc;n quan.</span></p>\r\n<p><span lang=\"EN-US\">Đối với th&agrave;nh vi&ecirc;n Chủ xe, cam kết kh&ocirc;ng vận chuyển h&agrave;ng qu&aacute; khổ - qu&aacute; tải khi chưa được sự cho ph&eacute;p của cơ quan chức năng. Trương hợp h&agrave;ng h&oacute;a cần giấy ph&eacute;p vận chuyển, Th&agrave;nh vi&ecirc;n Chủ xe phải tu&acirc;n thủ quy định xin cấp ph&eacute;p trước khi vận chuyển.</span></p>\r\n<p><span lang=\"EN-US\">S&agrave;n Ketnoivanchuyen.vn giữ quyền kiểm duyệt nội dung th&ocirc;ng tin đăng tải của th&agrave;nh vi&ecirc;n, v&agrave; bảo lưu quyền hủy th&ocirc;ng tin nếu x&eacute;t thấy th&ocirc;ng tin đ&atilde; đăng vi phạm quy định về vận tải h&agrave;ng h&oacute;a của Bộ Giao th&ocirc;ng vận tải, hoặc vi phạm về c&aacute;c quy định lưu th&ocirc;ng h&agrave;ng h&oacute;a của cơ quan chức năng kh&aacute;c.</span></p>\r\n<p><span lang=\"EN-US\">&nbsp;</span></p>\r\n<p><!-- [if !supportLists]--><strong><span lang=\"EN-US\">IX. </span><span lang=\"EN-US\">TR&Aacute;CH NHIỆM TRONG TRƯỜNG HỢP PH&Aacute;T SINH LỖI KĨ THUẬT: </span></strong></p>\r\n<p><span lang=\"EN-US\">Website ketnoivanchuyen.vn cam kết nỗ lực đảm bảo sự an to&agrave;n v&agrave; ổn định của to&agrave;n bộ hệ thống kỹ thuật. Tuy nhi&ecirc;n, trong trường hợp xảy ra sự cố do lỗi của Website ketnoivanchuyen.vn. ketnoivanchuyen.vn sẽ ngay lập tức &aacute;p dụng c&aacute;c biện ph&aacute;p để đảm bảo quyền lợi cho kh&aacute;ch h&agrave;ng.</span></p>\r\n<p><span lang=\"EN-US\">Khi thực hiện c&aacute;c giao dịch tr&ecirc;n Website ketnoivanchuyen.vn, bắt buộc c&aacute;c th&agrave;nh vi&ecirc;n phải thực hiện đ&uacute;ng theo c&aacute;c quy tr&igrave;nh hướng dẫn.</span></p>\r\n<p><span lang=\"EN-US\">Ban quản trị Website ketnoivanchuyen.vn cam kết cung cấp chất lượng dịch vụ tốt nhất cho c&aacute;c th&agrave;nh vi&ecirc;n tham gia giao dịch. Trường hợp ph&aacute;t sinh lỗi kỹ thuật, lỗi phần mềm hoặc c&aacute;c lỗi kh&aacute;ch quan kh&aacute;c dẫn đến th&agrave;nh vi&ecirc;n kh&ocirc;ng thể tham gia giao dịch được th&igrave; c&aacute;c Th&agrave;nh vi&ecirc;n th&ocirc;ng b&aacute;o cho Ban quản l&yacute; S&agrave;n giao dịch vận tải ketnoivanchuyen.vn, số điện thoại: +84 962 892 486, E-mail: info@ketnoivanchuyen.vn.</span></p>\r\n<p><span lang=\"EN-US\">Tuy nhi&ecirc;n, Ban quản trị Website ketnoivanchuyen.vn sẽ kh&ocirc;ng chịu tr&aacute;ch nhiệm giải quyết trong trường hợp th&ocirc;ng b&aacute;o của c&aacute;c th&agrave;nh vi&ecirc;n kh&ocirc;ng đến được ban quản trị, ph&aacute;t sinh từ lỗi kỹ thuật, lỗi đường truyền, phần mềm hoặc c&aacute;c lỗi kh&aacute;c kh&ocirc;ng do ban quản trị g&acirc;y ra. Đ&acirc;y l&agrave; những sự cố kh&ocirc;ng kiểm so&aacute;t được, do vậy ch&uacute;ng t&ocirc;i kh&ocirc;ng chịu tr&aacute;ch nhiệm về bất kỳ tổn thất ph&aacute;t sinh n&agrave;o từ những sự cố tr&ecirc;n g&acirc;y ra.</span></p>\r\n<p><span lang=\"EN-US\">Trong trường hợp hệ thống bị tấn c&ocirc;ng bởi t&aacute;c động b&ecirc;n ngo&agrave;i, ketnoivanchuyen.vn sẽ tiến h&agrave;nh ph&ograve;ng chống bằng c&aacute;ch phong tỏa đối tượng tấn c&ocirc;ng (IP, t&agrave;i khoản) v&agrave; phục hồi dữ liệu.</span></p>\r\n<p><span lang=\"EN-US\">Khi hệ thống server bị sự cố, Ketnoivanchuyen.vn sẽ sử dụng hệ thống server dự ph&ograve;ng v&agrave; khắc phục hậu quả sớm nhất.</span></p>\r\n<p><!-- [if !supportLists]--><strong><span lang=\"EN-US\">X. </span><span lang=\"EN-US\">QUYỀN V&Agrave; TR&Aacute;CH NHIỆM CỦA TH&Agrave;NH VI&Ecirc;N THAM GIA KETNOIVANCHUYEN.VN:</span></strong></p>\r\n<p><!-- [if !supportLists]--><strong><span lang=\"EN-US\">1. </span><span lang=\"EN-US\">Quyền của th&agrave;nh vi&ecirc;n tham gia S&agrave;n Giao dịch v&acirc;̣n tải ketnoivanchuyen.vn</span></strong></p>\r\n<p><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp; Được tham gia sử dụng dịch vụ do S&agrave;n giao dịch v&acirc;̣n tải ketnoivanchuyen.vn cung cấp.</span></p>\r\n<p><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp; Được quyền li&ecirc;n lạc với c&aacute;c bộ phận hỗ trợ của S&agrave;n giao dịch v&acirc;̣n tải ketnoivanchuyen.vn khi sử dụng dịch vụ, trước v&agrave; sau khi giao dịch.</span></p>\r\n<p><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp; Được quyền cung c&acirc;́p c&aacute;c th&ocirc;ng tin cơ bản li&ecirc;n quan đến giao dịch: loại xe, loại h&agrave;ng, tổng gi&aacute; trị giao dịch, thời gian v&acirc;̣n chuy&ecirc;̉n&hellip;</span></p>\r\n<p><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp; Được bảo vệ th&ocirc;ng tin c&aacute; nh&acirc;n tuyệt đối n&oacute;i tại đi&ecirc;̀u III, v&agrave; nếu S&agrave;n Giao dịch v&acirc;̣n tải ketnoivanchuyen.vn cung cấp th&ocirc;ng tin th&agrave;nh vi&ecirc;n cho b&ecirc;n thứ 3 phải c&oacute; sự cho ph&eacute;p của th&agrave;nh vi&ecirc;n, ngoại trừ c&aacute;c trường hợp theo y&ecirc;u cầu của cơ quan chức năng.</span></p>\r\n<p><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp; Được tham gia c&aacute;c chương tr&igrave;nh khuyến m&atilde;i, ưu đ&atilde;i kh&aacute;ch h&agrave;ng nếu đ&aacute;p ứng được quy chế chương tr&igrave;nh do S&agrave;n ketnoivanchuyen.vn ban h&agrave;nh.</span></p>\r\n<p><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp; Được quyền đề nghị S&agrave;n ketnoivanchuyen.vn trả lời thắc mắc, khiếu nại. Địa chỉ tiếp nhận:</span></p>\r\n<p><span lang=\"EN-US\">Email: </span><span lang=\"EN-US\"><a href=\"mailto:info@ketnoivanchuyen.vn\">info@ketnoivanchuyen.vn</a></span></p>\r\n<p><span lang=\"EN-US\">SĐT: 0962 892 486</span></p>\r\n<p><span lang=\"EN-US\">Địa chỉ: 164 Khuất Duy Tiến, Nh&acirc;n Ch&iacute;nh, Thanh Xu&acirc;n, H&agrave; Nội, Việt Nam. </span></p>\r\n<p><strong><span lang=\"EN-US\">2. Tr&aacute;ch nhiệm của th&agrave;nh vi&ecirc;n tham gia S&agrave;n ketnoivanchuyen.vn</span></strong></p>\r\n<p><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp; Tu&acirc;n thủ quy chế hoạt động, ch&iacute;nh s&aacute;ch do S&agrave;n ketnoivanchuyen.vn ban h&agrave;nh.</span></p>\r\n<p><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp; Đọc kỹ c&aacute;c th&ocirc;ng tin v&ecirc;̀ m&ocirc; tả v&ecirc;̀ xe của Chủ xe v&agrave; h&agrave;ng h&oacute;a của Chủ h&agrave;ng trước khi thực hi&ecirc;̣n giao dịch.</span></p>\r\n<p><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp; Chịu tr&aacute;ch nhiệm về c&aacute;c th&ocirc;ng tin cung cấp cho S&agrave;n giao dịch v&acirc;̣n tải ketnoivanchuyen.vn l&agrave; đ&uacute;ng v&agrave; x&aacute;c thực.</span></p>\r\n<p><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp; Chịu tr&aacute;ch nhiệm bảo mật t&agrave;i khoảnđăng nh&acirc;̣p website ketnoivanchuyen.vn của m&igrave;nh ở S&agrave;n giao dịch v&acirc;̣n tải Ketnoivanchuyen.vn.</span></p>\r\n<p><strong><span lang=\"EN-US\">3. Quy định đối với người tham gia S&agrave;n Giao dịch v&acirc;̣n tải ketnoivanchuyen.vn:</span></strong></p>\r\n<p><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp; Tu&acirc;n thủ quy chế hoạt động, ch&iacute;nh s&aacute;ch do ketnoivanchuyen.vn ban h&agrave;nh.</span></p>\r\n<p><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp;&nbsp; K&ecirc; khai đầy đủ th&ocirc;ng tin c&aacute; nh&acirc;n bằng tiếng Việt c&oacute; dấu: Họ v&agrave; t&ecirc;n đầy đủ, địa chỉ nhận h&agrave;ng (khu phố, phường, quận, th&agrave;nh phố);</span></p>\r\n<p><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp; K&ecirc; khai email v&agrave; số điện thoại c&oacute; thể li&ecirc;n lạc được;</span></p>\r\n<p><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp; Khi gửi Phản hồi v&agrave; Li&ecirc;n hệ tới Ban quản trị S&agrave;n giao dịch v&acirc;̣n tải ketnoivanchuyen.vn th&agrave;nh vi&ecirc;n cần gửi bằng Tiếng Việt c&oacute; dấu, hoặc Tiếng Anh.</span></p>\r\n<p><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp; Kh&ocirc;ng gửi những nội dung mang t&iacute;nh chất ph&aacute; hoại, sỉ nhục hay những nội dung vi phạm quy định thu&acirc;̀n phong mỹ tục của ph&aacute;p lu&acirc;̣t Vi&ecirc;̣t Nam.</span></p>\r\n<p><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp; Khi tham gia đấu thầu tr&ecirc;n S&agrave;n ketnoivanchuyen.vn th&agrave;nh vi&ecirc;n cần tu&acirc;n theo đ&uacute;ng c&aacute;c quy định, quy tr&igrave;nh về đấu thầu được th&ecirc;̉ hi&ecirc;̣n tại bản n&ocirc;̣i quy tham gia th&acirc;̀u.</span><span lang=\"EN-US\">&nbsp;</span></p>\r\n<p><!-- [if !supportLists]--><strong><span lang=\"EN-US\">XI. </span><span lang=\"EN-US\">QUYỀN V&Agrave; TR&Aacute;CH NHIỆM CỦA S&Agrave;N GIAO DỊCH VẬN TẢI KETNOIVANCHUYEN.VN</span></strong></p>\r\n<p><strong><span lang=\"EN-US\">1. Quyền của S&agrave;n giao dịch v&acirc;̣n tải ketnoivanchuyen.vn</span></strong></p>\r\n<p><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp; S&agrave;n ketnoivanchuyen.vn c&oacute; quyền từ chối những giao dịch vi phạm ph&aacute;p luật Việt Nam v&agrave; luật thương mại quốc tế.</span></p>\r\n<p><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp; S&agrave;n ketnoivanchuyen.vn quyền từ chối những giao dịch đi ngược lại thuần phong mỹ tục Việt Nam.-&nbsp;&nbsp;&nbsp; S&agrave;n ketnoivanchuyen.vn c&oacute; quyền từ chối hỗ trợ khiếu nại nếu lỗi thuộc về th&agrave;nh vi&ecirc;n kh&ocirc;ng đọc kỹ c&aacute;c th&ocirc;ng tin xe hoặc h&agrave;ngh&oacute;a của đ&ocirc;́i t&aacute;c.</span></p>\r\n<p><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp; S&agrave;n ketnoivanchuyen.vn c&oacute; quyền thay đổi c&aacute;c ch&iacute;nh s&aacute;ch li&ecirc;n quan v&agrave; sẽ c&oacute; hiệu lực sau 30 ng&agrave;y kể từ ng&agrave;y th&ocirc;ng b&aacute;o.</span></p>\r\n<p><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp; S&agrave;n ketnoivanchuyen.vn c&oacute; quyền kh&oacute;a c&aacute;c t&agrave;i khoản đăng nh&acirc;̣p th&agrave;nh vi&ecirc;n nếu th&agrave;nh vi&ecirc;n vi phạm c&aacute;c ch&iacute;nh s&aacute;ch hoạt động của S&agrave;n.</span></p>\r\n<p><strong><span lang=\"EN-US\">2. Tr&aacute;ch nhiệm của S&agrave;n giao dịch v&acirc;̣n tải ketnoivanchuyen.vn</span></strong></p>\r\n<p><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp; S&agrave;n Giao dịch v&acirc;̣n tải ketnoivanchuyen.vn c&oacute; tr&aacute;ch nhiệm kết nối c&aacute;c dữ liệu th&ocirc;ng tin về xe v&agrave; h&agrave;ng h&oacute;a tr&ecirc;n c&aacute;c website giao dịch v&acirc;̣n tải kh&aacute;c.</span></p>\r\n<p><span lang=\"EN-US\">-&nbsp;&nbsp;&nbsp; S&agrave;n Giao dich v&acirc;̣n tải ketnoivanchuyen.vn sẽ cố gắng hết sức để khắc phục nếu c&oacute; sự cố xảy ra như mất điện, hỏa hoạn, thi&ecirc;n tai ảnh hưởng đến quyền lợi của th&agrave;nh vi&ecirc;n. Tuy nhi&ecirc;n nếu những sự cố kh&aacute;ch quan n&agrave;y xảy ra nằm ngo&agrave;i kiểm so&aacute;t của S&agrave;n Giao dịch v&acirc;̣n tải Ketnoivanchuyen.vn g&acirc;y thiệt hại đến Th&agrave;nh vi&ecirc;n th&igrave; S&agrave;n ketnoivanchuyen.vn sẽ kh&ocirc;ng li&ecirc;n đới chịu tr&aacute;ch nhiệm.</span></p>\r\n<p><span lang=\"EN-US\">-&nbsp;&nbsp; Giải quyết - trả lời thắc mắc - khiếu nại của th&agrave;nh vi&ecirc;n khi nhận được th&ocirc;ng qua email tại địa chỉ:&nbsp; info@ketnoivanchuyen.vn.T&ugrave;y theo mức độ phức tạp của thắc mắc, khiếu nại của th&agrave;nh vi&ecirc;n, S&agrave;n ketnoivanchuyen.vn sẽ phản hồi người gửi trong v&ograve;ng tối đa 30 ng&agrave;y l&agrave;m việc.</span></p>\r\n<p><span lang=\"EN-US\">Trong trường hợp&nbsp; khiếu nại nằm ngo&agrave;i khả năng v&agrave; thẩm quyền của S&agrave;n ketnoivanchuyen.vn th&igrave; BQT sẽ y&ecirc;u cầu b&ecirc;n khiếu nại đưa vụ việc n&agrave;y ra cơ quan nh&agrave; nước c&oacute; thẩm quyền giải quyết theo ph&aacute;p luật.</span></p>\r\n<p><!-- [if !supportLists]--><strong><span lang=\"EN-US\">XII. </span><span lang=\"EN-US\">ĐIỀU KHOẢN &Aacute;P DỤNG </span></strong></p>\r\n<p><span lang=\"EN-US\">Quy chế hoạt động của S&agrave;n Giao dịch v&acirc;̣n tải Ketnoivanchuyen.vn c&oacute; hiệu lực ch&iacute;nh thức kể từ ng&agrave;y đăng l&ecirc;n Website Ketnoivanchuyen.vn. S&agrave;n Ketnoivanchuyen.vn c&oacute; quyền điều chỉnh, thay đổi, b&ocirc;̉ sung c&aacute;c đi&ecirc;̀u khoản của Quy chế n&agrave;y cho ph&ugrave; hợp với thực tiễn hoạt động v&agrave; c&oacute; tr&aacute;ch nhiệm th&ocirc;ng b&aacute;o l&ecirc;n Website Ketnoivanchuyen.vn cho c&aacute;c th&agrave;nh vi&ecirc;n biết. Quy chế sửa đổi c&oacute; hiệu lực sau 30 ng&agrave;y k&ecirc;̉ từ ng&agrave;y c&oacute; th&ocirc;ng b&aacute;o sửa đổi.</span></p>\r\n<p><span lang=\"EN-US\">S&agrave;n Giao dịch v&acirc;̣n tải Ketnoivanchuyen.vn v&agrave; Th&agrave;nh vi&ecirc;n đồng &yacute; cam kết thực hiện đ&uacute;ng c&aacute;c điều khoản trong nội dung Quy chế hoạt động n&agrave;y. Mọi tranh chấp ph&aacute;t sinh đều giải quyết tr&ecirc;n cơ sở thương lượng, nếu một trong hai b&ecirc;n thấy kh&ocirc;ng thỏa đ&aacute;ng, c&oacute; thể đưa vụ việc l&ecirc;n t&ograve;a &aacute;n kinh t&ecirc;́ Th&agrave;nh phố H&agrave; Nội giải quyết.</span></p>\r\n<p><!-- [if !supportLists]--><strong><span lang=\"EN-US\">XIII. </span><span lang=\"EN-US\">ĐIỀU KHOẢN CAM KẾT</span></strong></p>\r\n<p><span lang=\"EN-US\">Mọi th&agrave;nh vi&ecirc;n x&aacute;c nhận rằng đ&atilde; đọc v&agrave; hiểu những điều khoản dịch vụ của ketnoivanchuyen.vn v&agrave; đồng &yacute; những điều khoản v&agrave; điều kiện của dịch vụ n&agrave;y.</span></p>\r\n<p><span lang=\"EN-US\">Địa chỉ li&ecirc;n lạc ch&iacute;nh thức của S&agrave;n giao dịch website ketnoivanchuyen.vn</span></p>\r\n<p><span lang=\"EN-US\">C&ocirc;ng ty cổ phần Kết Nối Vận Chuyển To&agrave;n Cầu</span></p>\r\n<p><span lang=\"EN-US\">Địa chỉ: 164 Khuất Duy Tiến, Nh&acirc;n Ch&iacute;nh, Thanh Xu&acirc;n, H&agrave; Nội</span></p>\r\n<p><span lang=\"EN-US\">Điện thoại: 0962 892 486</span></p>\r\n<p><span lang=\"EN-US\">Li&ecirc;n hệ: info@ketnoivanchuyen.vn</span></p>\r\n<p><span lang=\"EN-US\">&nbsp;</span></p>\r\n<p><span lang=\"EN-US\">&nbsp;</span></p>\r\n<p><span lang=\"EN-US\">&nbsp;</span></p>', '2', 0, '1720689069');
